import{_ as a,v as t,f as o,i as r}from"./chunks/framework.jfF5glnW.js";const g=JSON.parse('{"title":"Week 10 | PCB 进阶设计与铺铜","description":"","frontmatter":{"title":"Week 10 | PCB 进阶设计与铺铜","date":"2026-05-05T00:00:00.000Z","tags":["课程周志","PCB设计","铺铜","立创EDA"],"cover":"/code2real_blog/posts/week10/gugugaga.jpg"},"headers":[],"relativePath":"posts/week10.md","filePath":"posts/week10.md"}'),s={name:"posts/week10.md"};function p(l,e,i,n,c,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<p>第十周继续学习 PCB 设计。本周重点放在更规范的布局布线、设计规则检查以及铺铜操作上。</p><hr><img src="/code2real_blog/posts/week10/gugugaga.jpg" alt="Week 10 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周的 PCB 学习不再停留在“把线连通”，而是进一步关注电路板是否更稳定、更规范。主要内容包括走线宽度设置、过孔使用、网络命名、间距规则、铺铜区域设置以及铺铜后的检查。</p><p>其中铺铜是本周的重点。铺铜不是单纯把空白区域填满，而是让某一网络在板面上形成较大面积连接，常见做法是连接 GND。这样可以减少回流路径阻抗，也能让板面电气结构更完整。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>实践时先检查元件布局，尽量让相关元件靠近，减少长距离绕线。随后根据不同网络调整走线，电源线适当加宽，普通信号线保持清晰，避免不必要的锐角和拥挤区域。</p><p>铺铜时先选择对应层和目标网络，再设置间距、热焊盘连接方式和孤岛铜处理。铺铜完成后，还需要重新运行设计规则检查，观察是否存在间距不足、未连接铜皮或局部残留问题。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>本周最明显的问题是铺铜后并不一定马上得到理想结果。有时铜皮看似铺满了，但实际存在孤岛铜，或者某些区域因为间距规则无法连接到目标网络。如果不检查，很容易误以为铺铜已经完成。</p><p>另一个问题是布线前期规划不足会影响后续铺铜效果。走线太乱、元件太挤、地网络被割裂，都会让铜皮连接变得不连续。这个问题说明铺铜不是最后补救步骤，而是需要和布局布线一起考虑。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>第十周让我对 PCB 设计的要求有了更清楚的认识。连通只是最低要求，真正可用的 PCB 还要考虑线宽、间距、回流路径、焊接便利性和规则检查。</p><p>通过铺铜练习，我开始理解地网络在电路板中的作用。PCB 设计不是简单画线，而是在有限空间内安排电气连接、制造条件和调试便利性。</p><img src="/code2real_blog/posts/week10/1.jpg" alt="Week 10 image"><img src="/code2real_blog/posts/week10/2.png" alt="Week 10 image">',17)])])}const h=a(s,[["render",p]]);export{g as __pageData,h as default};
